var doc = Rhino.RhinoDoc.ActiveDoc;
var counts = new Dictionary<int, int>();
foreach (var obj in doc.Objects)
{
    counts[obj.Attributes.LayerIndex] = (counts.TryGetValue(obj.Attributes.LayerIndex, out var n) ? n : 0) + 1;
}
var rows = new List<object>();
foreach (var layer in doc.Layers)
{
    rows.Add(new { index = layer.Index, name = layer.FullPath, visible = layer.IsVisible, count = counts.TryGetValue(layer.Index, out var c) ? c : 0 });
}
return new { layer_count = doc.Layers.Count, layers = rows };
